using System.ComponentModel;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var researchTools = new ResearchTools();

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Instructions = """
            You are a research agent. Your job is to research a topic thoroughly by:
            1. Searching the web for relevant information using multiple queries.
            2. Saving important findings as notes using the note-taking tool.
            3. After gathering enough information, retrieving all your notes and
               producing a well-structured summary.

            Always save key facts as notes before writing the final summary.
            Use at least 2-3 different search queries to get a broad perspective.
            """,
        Tools =
        [
            AIFunctionFactory.Create(researchTools.SearchWeb),
            AIFunctionFactory.Create(researchTools.SaveNote),
            AIFunctionFactory.Create(researchTools.GetNotes),
        ],
    });

Console.WriteLine("Research Agent");
Console.WriteLine(new string('=', 40));
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

await foreach (var response in agent.InvokeStreamingAsync(history, options))
{
    Console.Write(response.Text);
}

Console.WriteLine("\n\n" + new string('=', 40));
Console.WriteLine("Research complete.");

