using System.ComponentModel;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var researchTools = new ResearchTools();

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Instructions = """
            You are a research agent. Your job is to research a topic thoroughly by:
            1. Searching the web for relevant information using multiple queries.
            2. Saving important findings as notes using the note-taking tool.
            3. After gathering enough information, retrieving all your notes and
               producing a well-structured summary.

            Always save key facts as notes before writing the final summary.
            Use at least 2-3 different search queries to get a broad perspective.
            """,
        Tools =
        [
            AIFunctionFactory.Create(researchTools.SearchWeb),
            AIFunctionFactory.Create(researchTools.SaveNote),
            AIFunctionFactory.Create(researchTools.GetNotes),
        ],
    });

Console.WriteLine("Research Agent");
Console.WriteLine(new string('=', 40));
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

await foreach (var response in agent.InvokeStreamingAsync(history, options))
{
    Console.Write(response.Text);
}

Console.WriteLine("\n\n" + new string('=', 40));
Console.WriteLine("Research complete.");

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

public sealed class ResearchTools
{
    private readonly List<(string Title, string Content)> _notes = [];
    private readonly HttpClient _httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information. Returns a list of results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            _httpClient.DefaultRequestHeaders.Clear();
            _httpClient.DefaultRequestHeaders.Add("User-Agent", "ResearchAgent/1.0");

            var html = await _httpClient.GetStringAsync(url);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
            {
                return "No results found for this query.";
            }

            return string.Join("\n\n", results.Select((r, i) =>
                $"Result {i + 1}:\nTitle: {r.Title}\nSnippet: {r.Snippet}\nURL: {r.Url}"));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note with a title and content for later reference.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The note content with key findings")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");

        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        return string.Join("\n\n---\n\n", _notes.Select((n, i) =>
            $"Note {i + 1} — {n.Title}:\n{n.Content}"));
    }

    private static List<SearchResult> ParseSearchResults(string html)
    {
        var results = new List<SearchResult>();
        const int maxResults = 5;

        var searchIndex = 0;
        while (results.Count < maxResults)
        {
            var linkStart = html.IndexOf("class=\"result__a\"", searchIndex, StringComparison.Ordinal);
            if (linkStart < 0) break;

            var href = ExtractAttribute(html, linkStart, "href");
            var title = ExtractInnerText(html, linkStart);

            var snippetStart = html.IndexOf("class=\"result__snippet\"", linkStart, StringComparison.Ordinal);
            var snippet = snippetStart >= 0 ? ExtractInnerText(html, snippetStart) : "";

            if (!string.IsNullOrWhiteSpace(title))
            {
                results.Add(new SearchResult(
                    Title: CleanHtml(title),
                    Snippet: CleanHtml(snippet),
                    Url: CleanUrl(href)));
            }

            searchIndex = linkStart + 1;
        }

        return results;
    }

    private static string ExtractAttribute(string html, int startFrom, string attr)
    {
        var attrPattern = attr + "=\"";
        var idx = html.IndexOf(attrPattern, startFrom, StringComparison.Ordinal);
        if (idx < 0) return "";

        var valueStart = idx + attrPattern.Length;
        var valueEnd = html.IndexOf('"', valueStart);
        return valueEnd > valueStart ? html[valueStart..valueEnd] : "";
    }

    private static string ExtractInnerText(string html, int startFrom)
    {
        var tagEnd = html.IndexOf('>', startFrom);
        if (tagEnd < 0) return "";

        var contentStart = tagEnd + 1;
        var closingTag = html.IndexOf('<', contentStart);
        return closingTag > contentStart ? html[contentStart..closingTag] : "";
    }

    private static string CleanHtml(string text) =>
        System.Net.WebUtility.HtmlDecode(text).Trim();

    private static string CleanUrl(string url)
    {
        if (url.Contains("uddg=", StringComparison.Ordinal))
        {
            var start = url.IndexOf("uddg=", StringComparison.Ordinal) + 5;
            var end = url.IndexOf('&', start);
            var encoded = end > start ? url[start..end] : url[start..];
            return Uri.UnescapeDataString(encoded);
        }

        return url;
    }

    private sealed record SearchResult(string Title, string Snippet, string Url);
}

